// 🔥 FULLY UPDATED APP.JS (SRS COMPLIANT)

import React, { useState } from "react";

const GRACE_DAYS = 5;

const App = () => {
  const [role, setRole] = useState(null);

  const [lateFeePerDay, setLateFeePerDay] = useState(50);

  const [tenants, setTenants] = useState([
    {
      id: 1,
      name: "Rajesh",
      rent: 12500,
      dueDate: "2026-04-05",
    },
  ]);

  const [electricityBills, setElectricityBills] = useState([
    {
      tenantId: 1,
      oldReading: 100,
      newReading: 150,
      pricePerUnit: 10,
    },
  ]);

  const [payments, setPayments] = useState([]);

  // 🔥 LATE FEE CALCULATION
  const calculateLateFee = (tenant) => {
    const today = new Date();
    const due = new Date(tenant.dueDate);

    const diffDays = Math.floor(
      (today - due) / (1000 * 60 * 60 * 24)
    );

    const lateDays = diffDays - GRACE_DAYS;

    if (lateDays > 0) {
      return {
        lateDays,
        lateFee: lateDays * lateFeePerDay,
      };
    }

    return { lateDays: 0, lateFee: 0 };
  };

  // ⚡ ELECTRICITY CALCULATION
  const getElectricity = (tenantId) => {
    const bill = electricityBills.find(b => b.tenantId === tenantId);
    if (!bill) return 0;

    const units = bill.newReading - bill.oldReading;
    return units * bill.pricePerUnit;
  };

  // 💳 PAYMENT REQUEST
  const requestPayment = (tenant) => {
    const { lateDays, lateFee } = calculateLateFee(tenant);
    const electricity = getElectricity(tenant.id);

    const total =
      tenant.rent + electricity + lateFee;

    const newPayment = {
      id: Date.now(),
      tenantId: tenant.id,
      rent: tenant.rent,
      electricity,
      lateDays,
      lateFee,
      total,
      status: "Pending",
      date: new Date().toLocaleString(),
    };

    setPayments([...payments, newPayment]);
  };

  // ✅ APPROVE PAYMENT
  const approvePayment = (id) => {
    setPayments(payments.map(p =>
      p.id === id ? { ...p, status: "Approved" } : p
    ));
  };

  // ❌ REJECT PAYMENT
  const rejectPayment = (id) => {
    setPayments(payments.map(p =>
      p.id === id ? { ...p, status: "Rejected" } : p
    ));
  };

  if (!role) {
    return (
      <div style={{ padding: 40 }}>
        <h2>Select Role</h2>
        <button onClick={() => setRole("tenant")}>Tenant</button>
        <button onClick={() => setRole("admin")}>Landlord</button>
      </div>
    );
  }

  // ================= TENANT =================
  if (role === "tenant") {
    const tenant = tenants[0];
    const { lateDays, lateFee } = calculateLateFee(tenant);
    const electricity = getElectricity(tenant.id);

    const total =
      tenant.rent + electricity + lateFee;

    return (
      <div style={{ padding: 40 }}>
        <h2>Tenant Dashboard</h2>

        <p>Rent: ₹{tenant.rent}</p>
        <p>Electricity: ₹{electricity}</p>
        <p>
          Late Fee: ₹{lateFee} ({lateDays} days)
        </p>

        <h3>Total: ₹{total}</h3>

        <button onClick={() => requestPayment(tenant)}>
          Pay (Request Approval)
        </button>

        <h3>Status</h3>
        {payments.map(p => (
          <div key={p.id}>
            ₹{p.total} → {p.status}
          </div>
        ))}
      </div>
    );
  }

  // ================= ADMIN =================
  return (
    <div style={{ padding: 40 }}>
      <h2>Landlord Dashboard</h2>

      <h3>Set Late Fee</h3>
      <input
        value={lateFeePerDay}
        onChange={e => setLateFeePerDay(Number(e.target.value))}
      />

      <h3>Payment Requests</h3>

      {payments.map(p => (
        <div key={p.id} style={{ border: "1px solid #ccc", margin: 10, padding: 10 }}>
          <p>Tenant ID: {p.tenantId}</p>
          <p>Rent: ₹{p.rent}</p>
          <p>Electricity: ₹{p.electricity}</p>
          <p>Late Fee: ₹{p.lateFee} ({p.lateDays} days)</p>
          <p>Total: ₹{p.total}</p>
          <p>Status: {p.status}</p>

          {p.status === "Pending" && (
            <>
              <button onClick={() => approvePayment(p.id)}>Approve</button>
              <button onClick={() => rejectPayment(p.id)}>Reject</button>
            </>
          )}

          {/* 🧾 RECEIPT */}
          {p.status === "Approved" && (
            <div style={{ marginTop: 10, background: "#f5f5f5", padding: 10 }}>
              <h4>Receipt</h4>
              <p>Total Paid: ₹{p.total}</p>
              <p>Date: {p.date}</p>
            </div>
          )}
        </div>
      ))}
    </div>
  );
};

export default App;
